<?php
 namespace WPAICG\Images\Providers\Google; use WP_Error; if (!defined('ABSPATH')) { exit; } class GoogleVideoUrlBuilder { public static function build(string $model_id, array $api_params, string $operation = 'generate'): string|WP_Error { $base_url = !empty($api_params['base_url']) ? rtrim($api_params['base_url'], '/') : 'https://generativelanguage.googleapis.com'; $api_version = !empty($api_params['api_version']) ? $api_params['api_version'] : 'v1beta'; $api_key = !empty($api_params['api_key']) ? $api_params['api_key'] : ''; if (empty($api_key)) { return new WP_Error('missing_google_api_key_for_video_url', __('Google API key is required for video URL construction.', 'gpt3-ai-content-generator')); } if ($operation === 'generate') { $endpoint_suffix = ':predictLongRunning'; $full_path = '/' . trim($api_version, '/') . '/models/' . urlencode($model_id) . $endpoint_suffix; $url_with_key = $base_url . $full_path . '?key=' . urlencode($api_key); } elseif ($operation === 'poll') { $operation_name = $model_id; $full_path = '/' . trim($api_version, '/') . '/' . $operation_name; $url_with_key = $base_url . $full_path . '?key=' . urlencode($api_key); } else { return new WP_Error('unsupported_video_operation', sprintf(__('Unsupported video operation: %s', 'gpt3-ai-content-generator'), $operation)); } return $url_with_key; } } 